mapper.select:
SELECT
	ve.vehicle_id, ve.vehicle_name, ve.vehicle_name_ko, ve.category, ve.segment, ve.body_type,
	ve.seating, ve.min_price, ve.max_price, ve.description, ve.summary,
	ve.brand_id, ve.brand_name, ve.brand_name_ko,
	vd.url, vd.channel_name, vd.title
FROM vehicle ve
LEFT JOIN video vd ON ve.vehicle_id = vd.vehicle_id AND vd.display_order = 1


		ve.category = #{category}


		AND ve.segment IN

			#{seg}



		AND ve.vehicle_id IN (
			SELECT vehicle_id FROM vehicle_type WHERE fuel_type IN

				#{ft}

		)


		AND ve.max_price >= #{minPrice}


		AND ve.min_price <= #{maxPrice}


		AND ve.vehicle_name LIKE CONCAT('%', #{keyword}, '%')
